INSERT INTO coding_questions (title, slug, description, difficulty, topics, company_tags, examples, constraints, hints, test_cases, solution_template, source) VALUES
('Two Sum', 'two-sum', 'Given an array of integers nums and an integer target, return indices of the two numbers such that they add up to target.\n\nYou may assume that each input would have exactly one solution, and you may not use the same element twice.\n\nYou can return the answer in any order.', 'easy', '["Arrays", "Hash Table"]', '["Google", "Amazon", "Facebook"]', '[{"input": "nums = [2,7,11,15], target = 9", "output": "[0,1]", "explanation": "Because nums[0] + nums[1] == 9, we return [0, 1]."}, {"input": "nums = [3,2,4], target = 6", "output": "[1,2]", "explanation": ""}, {"input": "nums = [3,3], target = 6", "output": "[0,1]", "explanation": ""}]', '2 <= nums.length <= 10^4\n-10^9 <= nums[i] <= 10^9\n-10^9 <= target <= 10^9\nOnly one valid answer exists.', '["Use a hash map to store seen numbers", "Check if complement exists"]', '[{"input": "[2,7,11,15]\n9", "output": "[0,1]"}, {"input": "[3,2,4]\n6", "output": "[1,2]"}, {"input": "[3,3]\n6", "output": "[0,1]"}]', '{"python": "def twoSum(nums, target):\n    # Your code here\n    pass", "javascript": "function twoSum(nums, target) {\n    // Your code here\n}", "java": "public int[] twoSum(int[] nums, int target) {\n    // Your code here\n    return new int[0];\n}"}', 'leetcode'),
('Best Time to Buy and Sell Stock', 'best-time-to-buy-and-sell-stock', 'You are given an array prices where prices[i] is the price of a given stock on the ith day.\n\nYou want to maximize your profit by choosing a single day to buy one stock and choosing a different day in the future to sell that stock.\n\nReturn the maximum profit you can achieve from this transaction. If you cannot achieve any profit, return 0.', 'easy', '["Arrays", "Dynamic Programming"]', '["Amazon", "Microsoft", "Goldman Sachs"]', '[{"input": "prices = [7,1,5,3,6,4]", "output": "5", "explanation": "Buy on day 2 (price = 1) and sell on day 5 (price = 6), profit = 6-1 = 5."}, {"input": "prices = [7,6,4,3,1]", "output": "0", "explanation": "In this case, no transactions are done and the max profit = 0."}]', '1 <= prices.length <= 10^5\n0 <= prices[i] <= 10^4', '["Track minimum price seen so far", "Calculate profit for each day"]', '[{"input": "[7,1,5,3,6,4]", "output": "5"}, {"input": "[7,6,4,3,1]", "output": "0"}]', '{"python": "def maxProfit(prices):\n    # Your code here\n    pass", "javascript": "function maxProfit(prices) {\n    // Your code here\n}", "java": "public int maxProfit(int[] prices) {\n    // Your code here\n    return 0;\n}"}', 'leetcode'),
('Contains Duplicate', 'contains-duplicate', 'Given an integer array nums, return true if any value appears at least twice in the array, and return false if every element is distinct.', 'easy', '["Arrays", "Hash Table"]', '["Amazon", "Adobe"]', '[{"input": "nums = [1,2,3,1]", "output": "true", "explanation": ""}, {"input": "nums = [1,2,3,4]", "output": "false", "explanation": ""}, {"input": "nums = [1,1,1,3,3,4,3,2,4,2]", "output": "true", "explanation": ""}]', '1 <= nums.length <= 10^5\n-10^9 <= nums[i] <= 10^9', '["Use a set to track seen numbers"]', '[{"input": "[1,2,3,1]", "output": "true"}, {"input": "[1,2,3,4]", "output": "false"}]', '{"python": "def containsDuplicate(nums):\n    # Your code here\n    pass", "javascript": "function containsDuplicate(nums) {\n    // Your code here\n}", "java": "public boolean containsDuplicate(int[] nums) {\n    // Your code here\n    return false;\n}"}', 'leetcode'),
('Product of Array Except Self', 'product-of-array-except-self', 'Given an integer array nums, return an array answer such that answer[i] is equal to the product of all the elements of nums except nums[i].\n\nThe product of any prefix or suffix of nums is guaranteed to fit in a 32-bit integer.\n\nYou must write an algorithm that runs in O(n) time and without using the division operator.', 'medium', '["Arrays", "Prefix Sum"]', '["Amazon", "Facebook", "Microsoft"]', '[{"input": "nums = [1,2,3,4]", "output": "[24,12,8,6]", "explanation": ""}, {"input": "nums = [-1,1,0,-3,3]", "output": "[0,0,9,0,0]", "explanation": ""}]', '2 <= nums.length <= 10^5\n-30 <= nums[i] <= 30\nThe product of any prefix or suffix of nums is guaranteed to fit in a 32-bit integer.', '["Use two passes: left products and right products", "Avoid division by using prefix and suffix products"]', '[{"input": "[1,2,3,4]", "output": "[24,12,8,6]"}, {"input": "[-1,1,0,-3,3]", "output": "[0,0,9,0,0]"}]', '{"python": "def productExceptSelf(nums):\n    # Your code here\n    pass", "javascript": "function productExceptSelf(nums) {\n    // Your code here\n}", "java": "public int[] productExceptSelf(int[] nums) {\n    // Your code here\n    return new int[0];\n}"}', 'leetcode'),
('Maximum Subarray', 'maximum-subarray', 'Given an integer array nums, find the contiguous subarray (containing at least one number) which has the largest sum and return its sum.\n\nA subarray is a contiguous part of an array.', 'medium', '["Arrays", "Dynamic Programming", "Divide and Conquer"]', '["Amazon", "Microsoft", "LinkedIn"]', '[{"input": "nums = [-2,1,-3,4,-1,2,1,-5,4]", "output": "6", "explanation": "[4,-1,2,1] has the largest sum = 6."}, {"input": "nums = [1]", "output": "1", "explanation": ""}, {"input": "nums = [5,4,-1,7,8]", "output": "23", "explanation": ""}]', '1 <= nums.length <= 10^5\n-10^4 <= nums[i] <= 10^4', '["Kadane\'s algorithm", "Track maximum sum ending at current position"]', '[{"input": "[-2,1,-3,4,-1,2,1,-5,4]", "output": "6"}, {"input": "[1]", "output": "1"}]', '{"python": "def maxSubArray(nums):\n    # Your code here\n    pass", "javascript": "function maxSubArray(nums) {\n    // Your code here\n}", "java": "public int maxSubArray(int[] nums) {\n    // Your code here\n    return 0;\n}"}', 'leetcode');
INSERT INTO coding_questions (title, slug, description, difficulty, topics, company_tags, examples, constraints, hints, test_cases, solution_template, source) VALUES
('Valid Anagram', 'valid-anagram', 'Given two strings s and t, return true if t is an anagram of s, and false otherwise.\n\nAn Anagram is a word or phrase formed by rearranging the letters of a different word or phrase, typically using all the original letters exactly once.', 'easy', '["Strings", "Hash Table", "Sorting"]', '["Amazon", "Google"]', '[{"input": "s = \"anagram\", t = \"nagaram\"", "output": "true", "explanation": ""}, {"input": "s = \"rat\", t = \"car\"", "output": "false", "explanation": ""}]', '1 <= s.length, t.length <= 5 * 10^4\ns and t consist of lowercase English letters.', '["Count character frequencies", "Compare character counts"]', '[{"input": "\"anagram\"\n\"nagaram\"", "output": "true"}, {"input": "\"rat\"\n\"car\"", "output": "false"}]', '{"python": "def isAnagram(s, t):\n    # Your code here\n    pass", "javascript": "function isAnagram(s, t) {\n    // Your code here\n}", "java": "public boolean isAnagram(String s, String t) {\n    // Your code here\n    return false;\n}"}', 'leetcode'),
('Longest Substring Without Repeating Characters', 'longest-substring-without-repeating-characters', 'Given a string s, find the length of the longest substring without repeating characters.', 'medium', '["Strings", "Hash Table", "Sliding Window"]', '["Amazon", "Microsoft", "Bloomberg"]', '[{"input": "s = \"abcabcbb\"", "output": "3", "explanation": "The answer is \"abc\", with the length of 3."}, {"input": "s = \"bbbbb\"", "output": "1", "explanation": "The answer is \"b\", with the length of 1."}, {"input": "s = \"pwwkew\"", "output": "3", "explanation": "The answer is \"wke\", with the length of 3."}]', '0 <= s.length <= 5 * 10^4\ns consists of English letters, digits, symbols and spaces.', '["Use sliding window technique", "Track characters in current window"]', '[{"input": "\"abcabcbb\"", "output": "3"}, {"input": "\"bbbbb\"", "output": "1"}]', '{"python": "def lengthOfLongestSubstring(s):\n    # Your code here\n    pass", "javascript": "function lengthOfLongestSubstring(s) {\n    // Your code here\n}", "java": "public int lengthOfLongestSubstring(String s) {\n    // Your code here\n    return 0;\n}"}', 'leetcode'),
('Valid Parentheses', 'valid-parentheses', 'Given a string s containing just the characters \'(\', \')\', \'{\', \'}\', \'[\' and \']\', determine if the input string is valid.\n\nAn input string is valid if:\n1. Open brackets must be closed by the same type of brackets.\n2. Open brackets must be closed in the correct order.\n3. Every close bracket has a corresponding open bracket of the same type.', 'easy', '["Strings", "Stack"]', '["Amazon", "Google", "Microsoft"]', '[{"input": "s = \"()\"", "output": "true", "explanation": ""}, {"input": "s = \"()[]{}\"", "output": "true", "explanation": ""}, {"input": "s = \"(]\"", "output": "false", "explanation": ""}]', '1 <= s.length <= 10^4\ns consists of parentheses only \'()[]{}\'.', '["Use a stack to track opening brackets", "Match closing brackets with opening ones"]', '[{"input": "\"()\"", "output": "true"}, {"input": "\"(]\"", "output": "false"}]', '{"python": "def isValid(s):\n    # Your code here\n    pass", "javascript": "function isValid(s) {\n    // Your code here\n}", "java": "public boolean isValid(String s) {\n    // Your code here\n    return false;\n}"}', 'leetcode'),
('Group Anagrams', 'group-anagrams', 'Given an array of strings strs, group the anagrams together. You can return the answer in any order.\n\nAn Anagram is a word or phrase formed by rearranging the letters of a different word or phrase, typically using all the original letters exactly once.', 'medium', '["Strings", "Hash Table", "Sorting"]', '["Amazon", "Facebook", "Bloomberg"]', '[{"input": "strs = [\"eat\",\"tea\",\"tan\",\"ate\",\"nat\",\"bat\"]", "output": "[[\"bat\"],[\"nat\",\"tan\"],[\"ate\",\"eat\",\"tea\"]]", "explanation": ""}, {"input": "strs = [\"\"]", "output": "[[\"\"]]", "explanation": ""}, {"input": "strs = [\"a\"]", "output": "[[\"a\"]]", "explanation": ""}]', '1 <= strs.length <= 10^4\n0 <= strs[i].length <= 100\nstrs[i] consists of lowercase English letters.', '["Use sorted string as key", "Group strings with same sorted key"]', '[{"input": "[\"eat\",\"tea\",\"tan\",\"ate\",\"nat\",\"bat\"]", "output": "[[\"bat\"],[\"nat\",\"tan\"],[\"ate\",\"eat\",\"tea\"]]"}]', '{"python": "def groupAnagrams(strs):\n    # Your code here\n    pass", "javascript": "function groupAnagrams(strs) {\n    // Your code here\n}", "java": "public List<List<String>> groupAnagrams(String[] strs) {\n    // Your code here\n    return new ArrayList<>();\n}"}', 'leetcode');
INSERT INTO coding_questions (title, slug, description, difficulty, topics, company_tags, examples, constraints, hints, test_cases, solution_template, source) VALUES
('Maximum Depth of Binary Tree', 'maximum-depth-of-binary-tree', 'Given the root of a binary tree, return its maximum depth.\n\nA binary tree\'s maximum depth is the number of nodes along the longest path from the root node down to the farthest leaf node.', 'easy', '["Trees", "DFS", "BFS"]', '["Amazon", "Google", "Microsoft"]', '[{"input": "root = [3,9,20,null,null,15,7]", "output": "3", "explanation": ""}, {"input": "root = [1,null,2]", "output": "2", "explanation": ""}]', 'The number of nodes in the tree is in the range [0, 10^4].\n-100 <= Node.val <= 100', '["Use recursive DFS", "Base case: null node returns 0"]', '[{"input": "[3,9,20,null,null,15,7]", "output": "3"}]', '{"python": "def maxDepth(root):\n    # Your code here\n    pass", "javascript": "function maxDepth(root) {\n    // Your code here\n}", "java": "public int maxDepth(TreeNode root) {\n    // Your code here\n    return 0;\n}"}', 'leetcode'),
('Same Tree', 'same-tree', 'Given the roots of two binary trees p and q, write a function to check if they are the same or not.\n\nTwo binary trees are considered the same if they are structurally identical, and the nodes have the same value.', 'easy', '["Trees", "DFS"]', '["Amazon", "Google"]', '[{"input": "p = [1,2,3], q = [1,2,3]", "output": "true", "explanation": ""}, {"input": "p = [1,2], q = [1,null,2]", "output": "false", "explanation": ""}]', 'The number of nodes in both trees is in the range [0, 100].\n-10^4 <= Node.val <= 10^4', '["Recursively compare nodes", "Check structure and values"]', '[{"input": "[1,2,3]\n[1,2,3]", "output": "true"}]', '{"python": "def isSameTree(p, q):\n    # Your code here\n    pass", "javascript": "function isSameTree(p, q) {\n    // Your code here\n}", "java": "public boolean isSameTree(TreeNode p, TreeNode q) {\n    // Your code here\n    return false;\n}"}', 'leetcode'),
('Invert Binary Tree', 'invert-binary-tree', 'Given the root of a binary tree, invert the tree, and return its root.', 'easy', '["Trees", "DFS", "BFS"]', '["Google", "Amazon"]', '[{"input": "root = [4,2,7,1,3,6,9]", "output": "[4,7,2,9,6,3,1]", "explanation": ""}, {"input": "root = [2,1,3]", "output": "[2,3,1]", "explanation": ""}]', 'The number of nodes in the tree is in the range [0, 100].\n-100 <= Node.val <= 100', '["Swap left and right children recursively"]', '[{"input": "[4,2,7,1,3,6,9]", "output": "[4,7,2,9,6,3,1]"}]', '{"python": "def invertTree(root):\n    # Your code here\n    pass", "javascript": "function invertTree(root) {\n    // Your code here\n}", "java": "public TreeNode invertTree(TreeNode root) {\n    // Your code here\n    return null;\n}"}', 'leetcode');
INSERT INTO coding_questions (title, slug, description, difficulty, topics, company_tags, examples, constraints, hints, test_cases, solution_template, source) VALUES
('Climbing Stairs', 'climbing-stairs', 'You are climbing a staircase. It takes n steps to reach the top.\n\nEach time you can either climb 1 or 2 steps. In how many distinct ways can you climb to the top?', 'easy', '["Dynamic Programming", "Math"]', '["Amazon", "Google", "Adobe"]', '[{"input": "n = 2", "output": "2", "explanation": "There are two ways to climb to the top. 1. 1 step + 1 step 2. 2 steps"}, {"input": "n = 3", "output": "3", "explanation": "There are three ways to climb to the top. 1. 1 step + 1 step + 1 step 2. 1 step + 2 steps 3. 2 steps + 1 step"}]', '1 <= n <= 45', '["This is Fibonacci sequence", "Use DP: ways[i] = ways[i-1] + ways[i-2]"]', '[{"input": "2", "output": "2"}, {"input": "3", "output": "3"}]', '{"python": "def climbStairs(n):\n    # Your code here\n    pass", "javascript": "function climbStairs(n) {\n    // Your code here\n}", "java": "public int climbStairs(int n) {\n    // Your code here\n    return 0;\n}"}', 'leetcode'),
('Coin Change', 'coin-change', 'You are given an integer array coins representing coins of different denominations and an integer amount representing a total amount of money.\n\nReturn the fewest number of coins that you need to make up that amount. If that amount of money cannot be made up by any combination of the coins, return -1.\n\nYou may assume that you have an infinite number of each kind of coin.', 'medium', '["Dynamic Programming", "Array"]', '["Amazon", "Microsoft", "Goldman Sachs"]', '[{"input": "coins = [1,2,5], amount = 11", "output": "3", "explanation": "11 = 5 + 5 + 1"}, {"input": "coins = [2], amount = 3", "output": "-1", "explanation": ""}, {"input": "coins = [1], amount = 0", "output": "0", "explanation": ""}]', '1 <= coins.length <= 12\n1 <= coins[i] <= 2^31 - 1\n0 <= amount <= 10^4', '["Use DP: dp[i] = min coins for amount i", "For each coin, update dp[amount]"]', '[{"input": "[1,2,5]\n11", "output": "3"}, {"input": "[2]\n3", "output": "-1"}]', '{"python": "def coinChange(coins, amount):\n    # Your code here\n    pass", "javascript": "function coinChange(coins, amount) {\n    // Your code here\n}", "java": "public int coinChange(int[] coins, int amount) {\n    // Your code here\n    return -1;\n}"}', 'leetcode'),
('House Robber', 'house-robber', 'You are a professional robber planning to rob houses along a street. Each house has a certain amount of money stashed, the only constraint stopping you from robbing each of them is that adjacent houses have security systems connected and it will automatically contact the police if two adjacent houses were broken into on the same night.\n\nGiven an integer array nums representing the amount of money of each house, return the maximum amount of money you can rob tonight without alerting the police.', 'medium', '["Dynamic Programming", "Array"]', '["Amazon", "Google"]', '[{"input": "nums = [1,2,3,1]", "output": "4", "explanation": "Rob house 1 (money = 1) and then rob house 3 (money = 3). Total amount you can rob = 1 + 3 = 4."}, {"input": "nums = [2,7,9,3,1]", "output": "12", "explanation": "Rob house 1 (money = 2), rob house 3 (money = 9) and rob house 5 (money = 1). Total amount you can rob = 2 + 9 + 1 = 12."}]', '1 <= nums.length <= 100\n0 <= nums[i] <= 400', '["DP: rob[i] = max(rob[i-1], rob[i-2] + nums[i])", "Can\'t rob adjacent houses"]', '[{"input": "[1,2,3,1]", "output": "4"}, {"input": "[2,7,9,3,1]", "output": "12"}]', '{"python": "def rob(nums):\n    # Your code here\n    pass", "javascript": "function rob(nums) {\n    // Your code here\n}", "java": "public int rob(int[] nums) {\n    // Your code here\n    return 0;\n}"}', 'leetcode');
